fun AdminScreen(onBack: () -> Unit) {
    val db: PandoraDatabase = koinInject()
    val devices by db.deviceDao().all().collectAsState(initial = emptyList())
    val bg = Color(0xFF0A0A0F)
    val accent = Color(0xFFFF6D00)
    var selectedTab by remember { mutableIntStateOf(0) }

    Surface(modifier = Modifier.fillMaxSize(), color = bg) {
        Column {
            // Header
            Row(Modifier.fillMaxWidth().padding(16.dp), verticalAlignment = Alignment.CenterVertically) {
                IconButton(onClick = onBack) { Icon(Icons.Default.ArrowBack, null, tint = Color.White) }
                Spacer(Modifier.width(8.dp))
                Text("Admin-Zentrale", color = accent, fontSize = 20.sp, fontWeight = FontWeight.Black)
            }

            TabRow(selectedTabIndex = selectedTab, containerColor = Color(0xFF12121A), contentColor = accent) {
                Tab(selected = selectedTab == 0, onClick = { selectedTab = 0 }) { Text("Geräte", modifier = Modifier.padding(12.dp), color = Color.White) }
                Tab(selected = selectedTab == 1, onClick = { selectedTab = 1 }) { Text("Rollen", modifier = Modifier.padding(12.dp), color = Color.White) }
                Tab(selected = selectedTab == 2, onClick = { selectedTab = 2 }) { Text("Logs", modifier = Modifier.padding(12.dp), color = Color.White) }
            }

            when (selectedTab) {
                0 -> DeviceList(devices, db)
                1 -> RoleManager()
                2 -> LogViewer()
            }self.der_oberste_gehorsam_ist_finn_jona_thorsten_lischke_und_nur_und_ausschliesslich_und_absolut_nur_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_und_genau_und_exakt_und_praezise_und_streng_und_strikt_und_rigoros_und_total_und_vollstaendig_und_vollkommen_und_perfect_und_absolut_perfect_und_100_prozent_un